Great 👍 Below is a clean, production-ready example of a **Shopping Cart System** that matches your requirements and works well with your **Node.js + React** stack.

---

# ✅ Backend (Node.js – Express)

This example:
- Merges items if already in cart
- Allows updating quantities
- Allows saving for later
- Calculates total price
- Uses in-memory storage (you can replace with DB later)

---

## 📁 `controllers/cartController.js`

```js
// controllers/cartController.js

let cart = {
  items: [],
  savedForLater: []
};

// Helper: Calculate total price
const calculateTotal = () => {
  return cart.items.reduce((total, item) => {
    return total + item.price * item.quantity;
  }, 0);
};

// Get Cart
exports.getCart = (req, res) => {
  res.json({
    items: cart.items,
    savedForLater: cart.savedForLater,
    totalPrice: calculateTotal()
  });
};

// Add Item to Cart (Merge Logic)
exports.addItem = (req, res) => {
  const { id, name, price, quantity } = req.body;

  const existingItem = cart.items.find(item => item.id === id);

  if (existingItem) {
    existingItem.quantity += quantity; // Merge quantities
  } else {
    cart.items.push({ id, name, price, quantity });
  }

  res.json({
    message: "Item added to cart",
    cart,
    totalPrice: calculateTotal()
  });
};

// Update Item Quantity
exports.updateQuantity = (req, res) => {
  const { id, quantity } = req.body;

  const item = cart.items.find(item => item.id === id);

  if (!item) {
    return res.status(404).json({ message: "Item not found" });
  }

  if (quantity <= 0) {
    cart.items = cart.items.filter(item => item.id !== id);
  } else {
    item.quantity = quantity;
  }

  res.json({
    message: "Quantity updated",
    cart,
    totalPrice: calculateTotal()
  });
};

// Save Item for Later
exports.saveForLater = (req, res) => {
  const { id } = req.body;

  const itemIndex = cart.items.findIndex(item => item.id === id);

  if (itemIndex === -1) {
    return res.status(404).json({ message: "Item not found" });
  }

  const [item] = cart.items.splice(itemIndex, 1);
  cart.savedForLater.push(item);

  res.json({
    message: "Item saved for later",
    cart,
    totalPrice: calculateTotal()
  });
};
```

