# ✅ Frontend (React Cart Page)

This:
- Displays cart items
- Displays total price
- Allows quantity updates
- Allows save for later
- Uses Axios

---

## 📁 `src/pages/CartPage.js`

```jsx
import React, { useEffect, useState } from "react";
import axios from "axios";

const API = "http://localhost:5000/api/cart";

const CartPage = () => {
  const [cart, setCart] = useState({
    items: [],
    savedForLater: [],
    totalPrice: 0
  });

  const fetchCart = async () => {
    const res = await axios.get(API);
    setCart(res.data);
  };

  useEffect(() => {
    fetchCart();
  }, []);

  const updateQuantity = async (id, quantity) => {
    await axios.put(`${API}/update`, { id, quantity });
    fetchCart();
  };

  const saveForLater = async (id) => {
    await axios.post(`${API}/save`, { id });
    fetchCart();
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Shopping Cart</h2>

      {cart.items.length === 0 ? (
        <p>Your cart is empty</p>
      ) : (
        <>
          {cart.items.map(item => (
            <div key={item.id} style={{
              border: "1px solid #ccc",
              padding: "10px",
              marginBottom: "10px"
            }}>
              <h4>{item.name}</h4>
              <p>Price: ${item.price}</p>
              <p>
                Quantity:
                <input
                  type="number"
                  value={item.quantity}
                  min="1"
                  onChange={(e) =>
                    updateQuantity(item.id, parseInt(e.target.value))
                  }
                  style={{ marginLeft: "10px", width: "60px" }}
                />
              </p>
              <p>Subtotal: ${item.price * item.quantity}</p>

              <button onClick={() => saveForLater(item.id)}>
                Save for later
              </button>
            </div>
          ))}

          <h3>Total Price: ${cart.totalPrice}</h3>
        </>
      )}

      {cart.savedForLater.length > 0 && (
        <>
          <h2>Saved For Later</h2>
          {cart.savedForLater.map(item => (
            <div key={item.id} style={{
              border: "1px dashed gray",
              padding: "10px",
              marginBottom: "10px"
            }}>
              <h4>{item.name}</h4>
              <p>Price: ${item.price}</p>
            </div>
          ))}
        </>
      )}
    </div>
  );
};

export default CartPage;
```

